solution: class Solution {
public:
    const int MOD = 1'000'000'007;
    int countNumbers(string l, string r, int b) {
        auto solve = [&](const string& s) -> int {
            int n = s.size();
            vector<vector<int>> dp(n + 1, vector<int>(b, -1));
            function<int(int, int, bool)> dfs = [&](int pos, int prev, bool tight) -> int {
                if (pos == n) return 1;
                if (!tight && dp[pos][prev] != -1) return dp[pos][prev];
                int limit = tight ? (s[pos] - '0') : b - 1;
                int res = 0;
                for (int d = 0; d <= limit; ++d) {
                    if (pos == 0 && d == 0) continue;
                    if (d < prev) continue;
                    bool ntight = tight && (d == limit);
                    res = (res + dfs(pos + 1, d, ntight)) % MOD;
                }
                if (!tight) dp[pos][prev] = res;
                return res;
            };
            return dfs(0, 0, true);
        };
        auto valid = [&](const string& s) -> bool {
            for (int i = 1; i < (int)s.size(); ++i)
                if (s[i] < s[i-1]) return false;
            return true;
        };
        int upper = solve(r);
        int lower = solve(l);
        int ans = (upper - lower + MOD) % MOD;
        if (valid(l)) ans = (ans + 1) % MOD;
        return ans;
    }
};
